import { Button } from 'antd';

export const JournalManiaContainer = ({ onBack }) => {
  return (
      <div>
        <Button onClick={onBack}>Back to Overview</Button>
        <h2>Journal Mania</h2>
        <p>This is the Journal Mania project page. Here you can find details about the project, its features, and how it was developed.</p>
      </div>
  );
}
